export type CapturedPacket = { opcode: number; body: Uint8Array };

export function startMockWorldServer(opts?: {
  authStatus?: number;
  sendTimeSyncAfterLogin?: boolean;
}): Promise<{
  port: number;
  stop(): void;
  inject(opcode: number, body: Uint8Array): void;
  captured: CapturedPacket[];
  waitForCapture(
    predicate: (p: CapturedPacket) => boolean,
  ): Promise<CapturedPacket>;
}> {
  const authStatus = opts?.authStatus ?? 0x0c;
  const sendTimeSync = opts?.sendTimeSyncAfterLogin ?? false;
  let activeSocket: Socket<ConnState> | undefined;
  const captured: CapturedPacket[] = [];
  const captureListeners: CaptureListener[] = [];

  return new Promise((resolve) => {
    const listener: TCPSocketListener<ConnState> = Bun.listen({
      hostname: "127.0.0.1",
      port: 0,
      data: { buf: new Uint8Array(0) },
      socket: {
        open(socket) {
          activeSocket = socket;
          sendAuthChallenge(socket);
        },
        data(socket, data) {
          appendToBuffer(socket, new Uint8Array(data));
          drainPackets(
            socket,
            authStatus,
            sendTimeSync,
            captured,
            captureListeners,
          );
        },
        close() {
          activeSocket = undefined;
        },
      },
    });

    resolve({
      port: listener.port,
      stop() {
        listener.stop(true);
      },
      inject(opcode: number, body: Uint8Array) {
        if (!activeSocket) throw new Error("No active connection");
        activeSocket.write(
          buildServerPacket(opcode, body, activeSocket.data.arc4),
        );
      },
      captured,
      waitForCapture(predicate: (p: CapturedPacket) => boolean) {
        const existing = captured.find(predicate);
        if (existing) return Promise.resolve(existing);
        return new Promise<CapturedPacket>((resolve) => {
          captureListeners.push((packet) => {
            if (predicate(packet)) resolve(packet);
          });
        });
      },
    });
  });
}

